import{_ as t,p as e,q as d,a1 as a}from"./framework-96b046e1.js";const c={},i=a('<p>今天来记录一些 <code>Java</code> 中的修饰符，这些修饰符在编程中很重要经常会用到，新手经常会忘，所以在此记录一下。</p><ul><li>final</li><li>static</li><li>protected</li><li>public</li><li>private</li><li>abstract</li></ul><h2 id="final" tabindex="-1"><a class="header-anchor" href="#final" aria-hidden="true">#</a> final</h2><p><code>final</code> 可以对多种不同场景进行修饰，如：局部变量，类成员变量，对类，对成员函数等。</p><table><thead><tr><th>描述对象</th><th>解释</th></tr></thead><tbody><tr><td>对变量</td><td>代表该变量为不可变的，也就是常量，初始化后不可改变</td></tr><tr><td>对成员函数</td><td>子类不能重写</td></tr><tr><td>对类</td><td>final修饰的class不能被继承，不能当作基类</td></tr></tbody></table><h2 id="static" tabindex="-1"><a class="header-anchor" href="#static" aria-hidden="true">#</a> static</h2><p><code>static</code> 可以对多种不同场景进行修饰，如：类中的变量，对类，对成员函数等。</p><table><thead><tr><th>描述对象</th><th>解释</th></tr></thead><tbody><tr><td>对变量</td><td>1. 把变量变为类变量 2. 修改局部变量的声明周期</td></tr><tr><td>对成员函数</td><td>把函数变为类函数，通过类名调用的函数</td></tr><tr><td>对类</td><td>Java 中不能对顶级类使用 <code>static</code></td></tr><tr><td>对内部类</td><td>可以对内部类使用 <code>static</code></td></tr></tbody></table><div class="custom-container tip"><p class="custom-container-title">TIP</p><h3 id="static-内部类和非-static-内部类区别" tabindex="-1"><a class="header-anchor" href="#static-内部类和非-static-内部类区别" aria-hidden="true">#</a> <code>static</code> 内部类和非 <code>static</code> 内部类区别：</h3><ol><li><code>static</code> 内部类不需要指向外部类的引用</li><li><code>static</code> 内部类只能访问外部类的静态成员</li><li>非 <code>static</code> 内部类需要指向外部类的引用</li><li>非 <code>static</code> 内部类能够访问外部类的静态成员和非静态成员</li></ol></div><h2 id="protected" tabindex="-1"><a class="header-anchor" href="#protected" aria-hidden="true">#</a> protected</h2><p><code>protected</code>（受保护）,可以用在类中的变量和方法。</p><h3 id="顶级类非静态-protected" tabindex="-1"><a class="header-anchor" href="#顶级类非静态-protected" aria-hidden="true">#</a> 顶级类非静态 protected</h3><p><code>顶级类非静态 protected</code> 修饰的成员变量和成员函数只能在同一包里访问，不能在其他包中使用。</p><h3 id="顶级类静态-protected" tabindex="-1"><a class="header-anchor" href="#顶级类静态-protected" aria-hidden="true">#</a> 顶级类静态 protected</h3><p><code>顶级类静态 protected</code> 无论是否在同一个包中，在子类中均可直接访问。</p><p><code>顶级类静态 protected</code> 在不同包中，在非子类中不可访问。</p><h2 id="abstract-抽象" tabindex="-1"><a class="header-anchor" href="#abstract-抽象" aria-hidden="true">#</a> abstract 抽象</h2><p>抽象类不能实例化。</p><p><code>abstract</code> 可以修饰方法和类，如果类中有 <code>abstract</code> 方法则类也要用 <code>abstract</code> 进行修饰。</p>',19),r=[i];function o(s,h){return e(),d("div",null,r)}const n=t(c,[["render",o],["__file","modifier.html.vue"]]);export{n as default};
